<?php
namespace App\Modules\Hr\Training\Actions;
use App\Modules\Hr\Core\Services\HrAuditService; use App\Modules\Hr\Core\Services\TenantContext; use App\Modules\Hr\Training\Models\HrTrainingCourse;
class CreateTrainingCourseAction { public function __construct(private HrAuditService $audit){} public function execute(array $data):HrTrainingCourse{abort_unless(auth()->user()?->hasHrPermission('hr.training.manage'),403);$tenant=app(TenantContext::class)->getId();$code=strtoupper(trim((string)($data['code']??'')));$title=trim((string)($data['title']??''));$score=$data['passing_score']??null;$validity=$data['certificate_validity_months']??null;abort_if($code===''||$title===''||(int)($data['duration_minutes']??0)<0,422);abort_if($score!==null&&($score<0||$score>100),422,'Geçme puanı 0-100 arasında olmalıdır.');abort_if($validity!==null&&(int)$validity<1,422);abort_if(HrTrainingCourse::withoutGlobalScope('tenant')->where('legal_entity_id',$tenant)->where('code',$code)->exists(),422,'Eğitim kodu kullanılıyor.');$course=HrTrainingCourse::create(['legal_entity_id'=>$tenant,'code'=>$code,'title'=>$title,'category'=>$data['category']??null,'description'=>$data['description']??null,'duration_minutes'=>(int)($data['duration_minutes']??0),'passing_score'=>$score,'certificate_validity_months'=>$validity,'is_mandatory'=>(bool)($data['is_mandatory']??false),'is_active'=>true,'created_by'=>auth()->id()]);$this->audit->log('training_course_created',$course);return $course;} }
